toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     TodoCount="TodoTasks.Count"
                     InProgressCount="InProgressTasks.Count"
                     DoneCount="DoneTasks.Count"
                     OverdueCount="OverdueCount" />

    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="FilteredTodoTasks"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="args => CreateTask(args, \"To Do\")" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="FilteredInProgressTasks"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, \"To Do\")"
                     OnMoveRight="task => MoveTask(task, \"Done\")"
                     OnTaskCreated="args => CreateTask(args, \"In Progress\")" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="FilteredDoneTasks"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="args => CreateTask(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    // Unfiltered lists by status (for summary counts)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    // Filtered lists (search applied)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

